fn is_prime(n: i64) -> bool = {
    if n < 2 { false }
    else {
        let mut d: i64 = 2;
        let mut ok: bool = true;
        while d * d <= n {
            if n % d == 0 { ok = false } else { () };
            d = d + 1
        };
        ok
    }
};

fn nth_prime(n: i64) -> i64 = {
    let mut count: i64 = 0;
    let mut num: i64 = 1;
    while count < n {
        num = num + 1;
        if is_prime(num) { count = count + 1 } else { () }
    };
    num
};

